#include <bits/stdc++.h>
using namespace std;
int main(){int n,m;scanf("%d %d",&n,&m);vector<vector<long long>>p(n+1,vector<long long>(n+1,0));for(int i=1;i<=n;i++)for(int j=1;j<=n;j++){long long x;scanf("%lld",&x);p[i][j]=x+p[i-1][j]+p[i][j-1]-p[i-1][j-1];}string out;while(m--){int x1,y1,x2,y2;scanf("%d %d %d %d",&x1,&y1,&x2,&y2);out+=to_string(p[x2][y2]-p[x1-1][y2]-p[x2][y1-1]+p[x1-1][y1-1]);out+='\n';}fputs(out.c_str(),stdout);}
